1. components/admin/CopyLinkButton.tsx 생성:
   'use client'
   props: { invoiceId: string }
   state: copied = false (아이콘 교체용)

   const baseUrl = process.env.NEXT_PUBLIC_BASE_URL ?? (typeof window !== 'undefined' ? window.location.origin : '')
   const url = `${baseUrl}/invoice/${invoiceId}`

   const handleCopy = async () => {
     try {
       await navigator.clipboard.writeText(url)
       setCopied(true)
       toast.success('링크가 복사되었습니다')
       setTimeout(() => setCopied(false), 1500)
     } catch {
       toast.error('링크 복사에 실패했습니다')
     }
   }

   return (
     <Button variant="ghost" size="icon" onClick={handleCopy} title="링크 복사">
       {copied ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
       <span className="sr-only">링크 복사</span>
     </Button>
   )

